SELECT r.*, ste.site_nm AS site_nm, ord.member_nm AS order_nm, ite.prod_nm AS order_item_nm, mem.member_nm AS member_nm, cla.member_nm AS claim_nm, ite2.prod_nm AS claim_item_nm, vnd.vendor_nm AS vendor_nm, prd.prod_nm AS prod_id_nm, brd.brand_nm AS brand_id_nm, usr.user_nm AS md_user_nm, evt.event_nm AS promo_nm, cpn.coupon_nm AS coupon_nm, dis.discnt_nm AS discnt_nm, vou.voucher_nm AS voucher_nm, gif.gift_nm AS gift_nm, cd_rt.code_label AS raw_type_cd_nm, cd_rs.code_label AS raw_status_cd_nm, cd_ois.code_label AS order_item_status_cd_nm, cd_vt.code_label AS vendor_type_cd_nm, cd_pmc.code_label AS pay_method_cd_nm FROM st_settle_raw r LEFT JOIN sy_site ste ON ste.site_id = r.site_id LEFT JOIN od_order ord ON ord.order_id = r.order_id LEFT JOIN od_order_item ite ON ite.order_item_id = r.order_item_id LEFT JOIN mb_member mem ON mem.member_id = r.member_id LEFT JOIN od_claim cla ON cla.claim_id = r.claim_id LEFT JOIN od_claim_item ite2 ON ite2.claim_item_id = r.claim_item_id LEFT JOIN sy_vendor vnd ON vnd.vendor_id = r.vendor_id LEFT JOIN pd_prod prd ON prd.prod_id = r.prod_id LEFT JOIN sy_brand brd ON brd.brand_id = r.brand_id LEFT JOIN sy_user usr ON usr.user_id = r.md_user_id LEFT JOIN pm_event evt ON evt.event_id = r.promo_id LEFT JOIN pm_coupon cpn ON cpn.coupon_id = r.coupon_id LEFT JOIN pm_discnt dis ON dis.discnt_id = r.discnt_id LEFT JOIN pm_voucher vou ON vou.voucher_id = r.voucher_id LEFT JOIN pm_gift gif ON gif.gift_id = r.gift_id LEFT JOIN sy_code cd_rt ON cd_rt.code_grp = 'RAW_TYPE' AND cd_rt.code_value = r.raw_type_cd LEFT JOIN sy_code cd_rs ON cd_rs.code_grp = 'RAW_STATUS' AND cd_rs.code_value = r.raw_status_cd LEFT JOIN sy_code cd_ois ON cd_ois.code_grp = 'ORDER_ITEM_STATUS' AND cd_ois.code_value = r.order_item_status_cd LEFT JOIN sy_code cd_vt ON cd_vt.code_grp = 'VENDOR_TYPE' AND cd_vt.code_value = r.vendor_type_cd LEFT JOIN sy_code cd_pmc ON cd_pmc.code_grp = 'PAY_METHOD_CD' AND cd_pmc.code_value = r.pay_method_cd
ORDER BY r.settle_raw_id ASC ORDER BY r.settle_raw_id DESC ORDER BY r.prod_nm ASC ORDER BY r.prod_nm DESC ORDER BY r.order_date ASC ORDER BY r.order_date DESC ORDER BY r.reg_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

